internal final class UBSTriggerDimensionDefaultingList  extends RunBaseBatch
{
    DataAreaId sourceEntity;

    #define.CurrentVersion(1)
    #localmacro.CurrentList
        sourceEntity
    #endmacro

}

Method.Source:
    public boolean unpack(container packedClass)
    {
        Version version = runbase::getVersion(packedClass);
        switch (version)
        {
            case #CurrentVersion:
                [version, #CurrentList] = packedClass;
                break;
            default:
                return false;
        }

        return true;
    }

public DataAreaId parmSourceEntity(DataAreaId _sourceEntity = sourceEntity)
{
    sourceEntity = _sourceEntity;
    return sourceEntity;
}

server static UBSTriggerDimensionDefaultingList construct()
{
    return new UBSTriggerDimensionDefaultingList();
}

    static void main(Args args)
    {
        UBSTriggerDimensionDefaultingList import = UBSTriggerDimensionDefaultingList::construct();

        if (import.prompt())
        {
            import.runOperation();
        }
    }

public void run()
{
    VendTable vendTable;
        
        while select AccountNum from vendTable
        {
            UBSTriggerDimensionDefaultingMain defaultDimension = new UBSTriggerDimensionDefaultingMain();
            defaultDimension.updateDefaultDimension(sourceEntity, vendTable.AccountNum);
        }
}
